SELECT COUNT(*) AS registration_count
FROM registrations
WHERE level_id = (SELECT level_id FROM sponsorship_levels WHERE level_name = 'Gold');

SELECT level_name
FROM sponsorship_levels
WHERE price = (SELECT MAX(price) FROM sponsorship_levels);

SELECT level_name
FROM sponsorship_levels
ORDER BY level_id;

SELECT COUNT(*) AS num_high_benefit_levels
FROM sponsorship_levels
WHERE max_benefits > 5;

SELECT level_name, max_benefits
FROM sponsorship_levels
ORDER BY max_benefits DESC;

SELECT level_name
FROM sponsorship_levels
ORDER BY level_name;
